/* Test driver */
public class Main {
    public static void main(String[] args) {
        MessageBroker b = new MessageBroker(DeliveryGuarantee.AT_LEAST_ONCE);
        b.createTopic("t");
        ConcreteSubscriber a = new ConcreteSubscriber("A","SubA");
        ConcreteSubscriber c = new ConcreteSubscriber("C","SubC");
        b.subscribe("t", a);
        b.subscribe("t", c);
        Publisher p = new Publisher("P1","Pub1", b);
        p.publish("t","msg1");
        b.unsubscribe("t", a);
        p.publish("t","msg2");
        System.out.println(a.getMessagesReceived() == 1 ? "OK_A_GOT_1" : "FAIL");
        System.out.println(c.getMessagesReceived() == 2 ? "OK_C_GOT_2" : "FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        MessageBroker b = new MessageBroker(DeliveryGuarantee.AT_LEAST_ONCE);
        b.createTopic("t");
        ConcreteSubscriber s = new ConcreteSubscriber("S1","Sub1");
        b.subscribe("t", s);
        Publisher p = new Publisher("P1","Pub1", b);
        Message m = p.publish("t","x");
        MessageQueue q = b.getQueue(s);
        int sizeBefore = q.size();
        b.acknowledgeMessage(s, m.getMessageId());
        System.out.println(sizeBefore == 1 ? "OK_QSIZE_1" : "FAIL");
        System.out.println(q.getAcknowledgedCount() == 1 ? "OK_ACKED_1" : "FAIL");
    }
}

